import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as s,e as n}from"./app-be253e4c.js";const c={},t=n(`<h1 id="tmpwatch命令" tabindex="-1"><a class="header-anchor" href="#tmpwatch命令" aria-hidden="true">#</a> tmpwatch命令</h1><p><code>tmpwatch</code>递归删除给定时间内未访问的文件，通常用于清理用于临时存放空间的目录，并可以设置文件超期时间，默认单位以小时计算。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>tmpwatch <span class="token punctuation">[</span>-u <span class="token operator">|</span> <span class="token parameter variable">-m</span> <span class="token operator">|</span> -c<span class="token punctuation">]</span> <span class="token punctuation">[</span>-MUadfqstvx<span class="token punctuation">]</span> <span class="token punctuation">[</span>--verbose<span class="token punctuation">]</span> <span class="token punctuation">[</span>--force<span class="token punctuation">]</span> <span class="token punctuation">[</span>--all<span class="token punctuation">]</span> <span class="token punctuation">[</span>--nodirs<span class="token punctuation">]</span> <span class="token punctuation">[</span>--nosymlinks<span class="token punctuation">]</span> <span class="token punctuation">[</span>--test<span class="token punctuation">]</span> <span class="token punctuation">[</span>--fuser<span class="token punctuation">]</span> <span class="token punctuation">[</span>--quiet<span class="token punctuation">]</span> <span class="token punctuation">[</span>--atime <span class="token operator">|</span> <span class="token parameter variable">--mtime</span> <span class="token operator">|</span> --ctime<span class="token punctuation">]</span> <span class="token punctuation">[</span>--dirmtime<span class="token punctuation">]</span> <span class="token punctuation">[</span>--exclude path <span class="token punctuation">]</span> <span class="token punctuation">[</span>--exclude-user user <span class="token punctuation">]</span> <span class="token function">time</span> <span class="token function">dirs</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-a, --all</code>: 删除所有文件类型，而不仅仅是常规文件，符号链接和目录。</li><li><code>-c, --ctime</code>: 根据文件的<code>ctime</code>即<code>inode</code>更改时间，而不是<code>atime</code>来决定删除文件，对于目录根据<code>mtime</code>做出是否删除的决定。</li><li><code>-d, --nodirs</code>: 即使目录为空，也不要尝试删除它们。</li><li><code>-f, --force</code>: 即使<code>root</code>没有写访问权限，也删除文件类似于<code>rm -f</code>。</li><li><code>-l, --nosymlinks</code>: 不要尝试删除符号链接。</li><li><code>-m, --mtime</code>: 根据文件的<code>mtime</code>即修改时间而不是<code>atime</code>来决定删除文件。</li><li><code>-M, --dirmtime</code>: 根据目录的<code>mtime</code>即修改时间而不是<code>atime</code>来决定删除目录，完全忽略目录时间。</li><li><code>-q, --quiet</code>: 仅报告致命错误。</li><li><code>-s, --fuser</code>: 尝试使用<code>fuser</code>命令来查看文件是否已打开，然后再将其删除，默认情况下未启用，在某些情况下确实有帮助。</li><li><code>-t, --test</code>: 不要删除文件，但要执行删除它们的动作，这意味着<code>-v</code>。</li><li><code>-u, --atime</code>: 根据文件的访问时间来决定是否删除文件，这是默认值，请注意定期的<code>updatedb</code>文件系统扫描会保留最近的目录时间。</li><li><code>-U, --exclude-user=user</code>: 不要删除用户拥有的文件，该文件可以是用户名或数字用户<code>ID</code>。</li><li><code>-v, --verbose</code>: 打印详细显示，有两种详细级别可用。</li><li><code>-x, --exclude=path</code>: 跳过路径，如果<code>path</code>是目录，则包含在其中的所有文件也会被跳过，如果路径不存在，则它必须是不包含符号链接的绝对路径。</li><li><code>-X, --exclude-pattern=pattern</code>: 跳过路径匹配模式，如果目录与<code>pattern</code>匹配，其中的所有文件也将被跳过，模式必须匹配不包含符号链接的绝对路径。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>要从<code>/var/log/</code>日志目录中删除<code>30d</code>以上未访问的文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>tmpwatch 30d /var/log/
</code></pre></div><p>列出<code>/tmp/</code>缓存目录中至少<code>30</code>小时未修改的所有文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>tmpwatch –mtime <span class="token number">30</span> –nodirs /tmp/ –test
</code></pre></div><p>删除<code>/tmp/</code>缓存目录中至少<code>30</code>个小时未访问的所有文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>tmpwatch <span class="token parameter variable">-am</span> <span class="token number">30</span> –nodirs /tmp/
</code></pre></div>`,13),o=[t];function p(d,i){return e(),s("div",null,o)}const r=a(c,[["render",p],["__file","tmpwatch.html.vue"]]);export{r as default};
